/**
 * Utilitários para filtrar operações fechadas
 * Implementa a lógica de "totalmente realizado" do backend
 */

/**
 * Filtra operações que foram totalmente realizadas (100% fechadas)
 * @param {Array} trades - Array de trades
 * @returns {Array} - Trades filtrados
 */
export const filterFullyRealizedTrades = (trades) => {
  if (!Array.isArray(trades)) {
    console.warn('⚠️ filterFullyRealizedTrades: trades não é um array');
    return [];
  }

  return trades.filter(trade => {
    // Verificar se o trade tem os campos necessários
    if (!trade || typeof trade !== 'object') {
      return false;
    }

    // Critérios para operação totalmente realizada:
    // 1. Status deve ser 'closed'
    // 2. Deve ter PnL realizado (diferente de 0)
    // 3. Deve ter preço de saída definido
    // 4. Deve ter data de fechamento

    const isStatusClosed = trade.status === 'closed';
    const hasPnl = trade.pnl !== undefined && trade.pnl !== null && trade.pnl !== 0;
    const hasExitPrice = trade.exit_price !== undefined && trade.exit_price !== null && trade.exit_price > 0;
    const hasClosedDate = trade.closed_at !== undefined && trade.closed_at !== null;

    const isFullyRealized = isStatusClosed && hasPnl && hasExitPrice && hasClosedDate;

    if (!isFullyRealized) {
      console.log(`🔍 Trade ${trade.id} não totalmente realizado:`, {
        symbol: trade.symbol,
        status: trade.status,
        pnl: trade.pnl,
        exit_price: trade.exit_price,
        closed_at: trade.closed_at,
        isStatusClosed,
        hasPnl,
        hasExitPrice,
        hasClosedDate
      });
    }

    return isFullyRealized;
  });
};

/**
 * Filtra operações por período de tempo
 * @param {Array} trades - Array de trades
 * @param {string} period - Período: 'today', 'week', 'month', 'all'
 * @returns {Array} - Trades filtrados
 */
export const filterTradesByPeriod = (trades, period = 'all') => {
  if (!Array.isArray(trades)) {
    return [];
  }

  if (period === 'all') {
    return trades;
  }

  const now = new Date();
  let startDate;

  switch (period) {
    case 'today':
      startDate = new Date(now.getFullYear(), now.getMonth(), now.getDate());
      break;
    case 'week':
      startDate = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
      break;
    case 'month':
      startDate = new Date(now.getFullYear(), now.getMonth(), 1);
      break;
    default:
      return trades;
  }

  return trades.filter(trade => {
    if (!trade.closed_at) {
      return false;
    }

    const tradeDate = new Date(trade.closed_at);
    return tradeDate >= startDate;
  });
};

/**
 * Filtra operações por símbolo
 * @param {Array} trades - Array de trades
 * @param {string} symbol - Símbolo para filtrar (ex: 'BTCUSDT')
 * @returns {Array} - Trades filtrados
 */
export const filterTradesBySymbol = (trades, symbol) => {
  if (!Array.isArray(trades) || !symbol) {
    return trades;
  }

  return trades.filter(trade => 
    trade.symbol && trade.symbol.toLowerCase().includes(symbol.toLowerCase())
  );
};

/**
 * Filtra operações por lado (long/short)
 * @param {Array} trades - Array de trades
 * @param {string} side - Lado: 'long', 'short', 'buy', 'sell'
 * @returns {Array} - Trades filtrados
 */
export const filterTradesBySide = (trades, side) => {
  if (!Array.isArray(trades) || !side) {
    return trades;
  }

  return trades.filter(trade => {
    if (!trade.side) {
      return false;
    }

    const tradeSide = trade.side.toLowerCase();
    const filterSide = side.toLowerCase();

    // Normalizar diferentes formatos
    if (filterSide === 'long' && (tradeSide === 'long' || tradeSide === 'buy')) {
      return true;
    }
    if (filterSide === 'short' && (tradeSide === 'short' || tradeSide === 'sell')) {
      return true;
    }

    return tradeSide === filterSide;
  });
};

/**
 * Filtra operações por resultado (lucro/prejuízo)
 * @param {Array} trades - Array de trades
 * @param {string} result - Resultado: 'profit', 'loss', 'all'
 * @returns {Array} - Trades filtrados
 */
export const filterTradesByResult = (trades, result = 'all') => {
  if (!Array.isArray(trades) || result === 'all') {
    return trades;
  }

  return trades.filter(trade => {
    const pnl = parseFloat(trade.pnl) || 0;

    switch (result) {
      case 'profit':
        return pnl > 0;
      case 'loss':
        return pnl < 0;
      default:
        return true;
    }
  });
};

/**
 * Aplica múltiplos filtros às operações
 * @param {Array} trades - Array de trades
 * @param {Object} filters - Objeto com filtros
 * @returns {Array} - Trades filtrados
 */
export const applyTradeFilters = (trades, filters = {}) => {
  let filteredTrades = [...trades];

  // Aplicar filtro de totalmente realizado primeiro
  if (filters.fullyRealized === true) {
    filteredTrades = filterFullyRealizedTrades(filteredTrades);
  }

  // Aplicar filtro de período
  if (filters.period) {
    filteredTrades = filterTradesByPeriod(filteredTrades, filters.period);
  }

  // Aplicar filtro de símbolo
  if (filters.symbol) {
    filteredTrades = filterTradesBySymbol(filteredTrades, filters.symbol);
  }

  // Aplicar filtro de lado
  if (filters.side) {
    filteredTrades = filterTradesBySide(filteredTrades, filters.side);
  }

  // Aplicar filtro de resultado
  if (filters.result) {
    filteredTrades = filterTradesByResult(filteredTrades, filters.result);
  }

  console.log(`🔍 Filtros aplicados:`, filters);
  console.log(`📊 Trades antes dos filtros: ${trades.length}`);
  console.log(`📊 Trades após filtros: ${filteredTrades.length}`);

  return filteredTrades;
};

/**
 * Valida se um trade está completo e pode ser exibido
 * @param {Object} trade - Trade para validar
 * @returns {boolean} - Se o trade é válido
 */
export const isValidTrade = (trade) => {
  if (!trade || typeof trade !== 'object') {
    return false;
  }

  // Campos obrigatórios
  const requiredFields = ['id', 'symbol', 'side', 'status'];

  for (const field of requiredFields) {
    if (!trade[field]) {
      console.warn(`⚠️ Trade ${trade.id || 'unknown'} está faltando campo obrigatório: ${field}`);
      return false;
    }
  }

  return true;
};

export default {
  filterFullyRealizedTrades,
  filterTradesByPeriod,
  filterTradesBySymbol,
  filterTradesBySide,
  filterTradesByResult,
  applyTradeFilters,
  isValidTrade
};
